const { ApolloServer, gql } = require('apollo-server');

const typeDefs = gql`
  type Invoice {
    id: ID!
    invoiceNumber: String!
    customerId: ID!
    customerName: String!
    customerEmail: String!
    issueDate: String!
    dueDate: String!
    status: InvoiceStatus!
    items: [InvoiceItem!]!
    subtotal: Float!
    tax: Float!
    total: Float!
    notes: String
    createdAt: String!
    updatedAt: String!
  }

  type InvoiceItem {
    id: ID!
    description: String!
    quantity: Int!
    unitPrice: Float!
    amount: Float!
  }

  enum InvoiceStatus {
    DRAFT
    SENT
    PAID
    OVERDUE
    CANCELLED
  }

  type Query {
    invoice(id: ID!): Invoice
  }
`;

